"use strict";(globalThis.webpackChunklearncpp_docs=globalThis.webpackChunklearncpp_docs||[]).push([[8998],{71e3(n,r,o){o.r(r),o.d(r,{assets:()=>i,contentTitle:()=>l,default:()=>d,frontMatter:()=>s,metadata:()=>t,toc:()=>a});const t=JSON.parse('{"id":"cpp20/source-location","title":"std::source_location","description":"C++20 std::source_location \u6559\u5b66\u793a\u4f8b","source":"@site/docs/cpp20/43-source-location.md","sourceDirName":"cpp20","slug":"/cpp20/43-source-location","permalink":"/LearnModernCpp/docs/cpp20/43-source-location","draft":false,"unlisted":false,"tags":[{"inline":true,"label":"cpp20","permalink":"/LearnModernCpp/docs/tags/cpp-20"},{"inline":true,"label":"source_location","permalink":"/LearnModernCpp/docs/tags/source-location"}],"version":"current","sidebarPosition":44,"frontMatter":{"sidebar_position":44,"slug":"43-source-location","title":"std::source_location","description":"C++20 std::source_location \u6559\u5b66\u793a\u4f8b","tags":["cpp20","source_location"]},"sidebar":"docs","previous":{"title":"chrono \u65e5\u5386\u548c\u65f6\u533a (Calendar and Time Zone)","permalink":"/LearnModernCpp/docs/cpp20/42-calendar-timezone"},"next":{"title":"std::bit_cast","permalink":"/LearnModernCpp/docs/cpp20/44-bit-cast"}}');var e=o(74848),c=o(28453);const s={sidebar_position:44,slug:"43-source-location",title:"std::source_location",description:"C++20 std::source_location \u6559\u5b66\u793a\u4f8b",tags:["cpp20","source_location"]},l="std::source_location",i={},a=[{value:"\u5b8c\u6574\u6e90\u7801",id:"\u5b8c\u6574\u6e90\u7801",level:2},{value:"\u53c2\u8003\u94fe\u63a5",id:"\u53c2\u8003\u94fe\u63a5",level:2}];function u(n){const r={a:"a",code:"code",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",pre:"pre",ul:"ul",...(0,c.R)(),...n.components};return(0,e.jsxs)(e.Fragment,{children:[(0,e.jsx)(r.header,{children:(0,e.jsx)(r.h1,{id:"stdsource_location",children:"std::source_location"})}),"\n",(0,e.jsx)(r.p,{children:"C++20 \u6807\u51c6\u5f15\u5165\u7684 std::source_location \u7279\u6027\u5b8c\u6574\u6559\u5b66\u793a\u4f8b\u3002"}),"\n",(0,e.jsx)(r.h2,{id:"\u5b8c\u6574\u6e90\u7801",children:"\u5b8c\u6574\u6e90\u7801"}),"\n",(0,e.jsx)(r.pre,{children:(0,e.jsx)(r.code,{className:"language-cpp",metastring:'title="cpp20/43_source_location.cpp"',children:'/**\r\n * ============================================================\r\n * \u7279\u6027\u540d\u79f0: std::source_location\r\n * \u6240\u5c5e\u6807\u51c6: C++20\r\n * ============================================================\r\n *\r\n * [\u662f\u4ec0\u4e48]: std::source_location \u63d0\u4f9b\u4e86\u83b7\u53d6\u6e90\u4ee3\u7801\u4f4d\u7f6e\u4fe1\u606f\u7684\u6807\u51c6\u65b9\u5f0f\uff0c\r\n *          \u5305\u62ec\u6587\u4ef6\u540d\u3001\u884c\u53f7\u3001\u5217\u53f7\u548c\u51fd\u6570\u540d\u3002\r\n *\r\n * [\u4e3a\u4ec0\u4e48\u5f15\u5165]: \u66ff\u4ee3\u4f20\u7edf\u7684 __FILE__\u3001__LINE__\u3001__func__ \u9884\u5904\u7406\u5b8f\uff0c\r\n *             \u63d0\u4f9b\u66f4\u5b89\u5168\u3001\u66f4\u7075\u6d3b\u3001\u66f4 C++ \u5316\u7684\u65b9\u5f0f\u3002\r\n *             \u7279\u522b\u662f\u5728\u65e5\u5fd7\u548c\u65ad\u8a00\u4e2d\u4f7f\u7528\u65f6\uff0c\u4e0d\u9700\u8981\u5b8f\u5c55\u5f00\u3002\r\n *\r\n * [\u5173\u952e\u8981\u70b9]:\r\n *   - source_location::current() \u83b7\u53d6\u8c03\u7528\u70b9\u7684\u4fe1\u606f\r\n *   - \u63d0\u4f9b file_name()\u3001line()\u3001column()\u3001function_name()\r\n *   - \u53ef\u4ee5\u4f5c\u4e3a\u51fd\u6570\u9ed8\u8ba4\u53c2\u6570\u4f7f\u7528\uff08\u5173\u952e\u7528\u6cd5\uff09\r\n *   - \u66ff\u4ee3 __FILE__ \u548c __LINE__ \u5b8f\r\n * ============================================================\r\n */\r\n\r\n#include <iostream>\r\n#include <string>\r\n#include <string_view>\r\n#include <vector>\r\n#include <source_location>\r\n\r\n// ===================== basic_usage() =====================\r\n\r\n// \u57fa\u672c\u4f7f\u7528\uff1a\u83b7\u53d6\u5f53\u524d\u4f4d\u7f6e\r\nvoid print_location(const std::source_location& loc = std::source_location::current()) {\r\n    std::cout << "  \u6587\u4ef6: " << loc.file_name() << "\\n";\r\n    std::cout << "  \u884c\u53f7: " << loc.line() << "\\n";\r\n    std::cout << "  \u5217\u53f7: " << loc.column() << "\\n";\r\n    std::cout << "  \u51fd\u6570: " << loc.function_name() << "\\n";\r\n}\r\n\r\nvoid basic_usage() {\r\n    std::cout << "--- \u57fa\u7840\u7528\u6cd5 ---\\n\\n";\r\n\r\n    // \u76f4\u63a5\u83b7\u53d6\u5f53\u524d\u4f4d\u7f6e\r\n    auto loc = std::source_location::current();\r\n    std::cout << "\u5f53\u524d\u4f4d\u7f6e:\\n";\r\n    std::cout << "  \u6587\u4ef6: " << loc.file_name() << "\\n";\r\n    std::cout << "  \u884c\u53f7: " << loc.line() << "\\n";\r\n    std::cout << "  \u51fd\u6570: " << loc.function_name() << "\\n";\r\n\r\n    // \u4f5c\u4e3a\u9ed8\u8ba4\u53c2\u6570\u4f7f\u7528\uff08\u5173\u952e\u7528\u6cd5\uff01\uff09\r\n    // print_location \u7684\u9ed8\u8ba4\u53c2\u6570\u4f1a\u81ea\u52a8\u6355\u83b7\u8c03\u7528\u70b9\u7684\u4f4d\u7f6e\r\n    std::cout << "\\n\u8c03\u7528 print_location() (\u81ea\u52a8\u6355\u83b7\u8c03\u7528\u70b9):\\n";\r\n    print_location();  // \u8fd9\u91cc\u7684\u884c\u53f7\u662f\u8c03\u7528\u70b9\uff0c\u4e0d\u662f print_location \u5185\u90e8\r\n\r\n    std::cout << "\\n\u4e0e\u4f20\u7edf\u5b8f\u5bf9\u6bd4:\\n";\r\n    std::cout << "  __FILE__: " << __FILE__ << "\\n";\r\n    std::cout << "  __LINE__: " << __LINE__ << "\\n";\r\n    // __func__ \u53ea\u5728\u51fd\u6570\u5185\u90e8\u53ef\u7528\r\n    std::cout << "  __func__: " << __func__ << "\\n";\r\n}\r\n\r\n// ===================== advanced_usage() =====================\r\n\r\n// \u65e5\u5fd7\u7cfb\u7edf\r\nenum class LogLevel { DEBUG, INFO, WARNING, ERROR };\r\n\r\nstd::string_view level_to_string(LogLevel level) {\r\n    switch (level) {\r\n        case LogLevel::DEBUG:   return "\u8c03\u8bd5";\r\n        case LogLevel::INFO:    return "\u4fe1\u606f";\r\n        case LogLevel::WARNING: return "\u8b66\u544a";\r\n        case LogLevel::ERROR:   return "\u9519\u8bef";\r\n    }\r\n    return "\u672a\u77e5";\r\n}\r\n\r\n// \u65e5\u5fd7\u51fd\u6570\uff1a\u81ea\u52a8\u83b7\u53d6\u8c03\u7528\u4f4d\u7f6e\r\nvoid log(LogLevel level, std::string_view message,\r\n         const std::source_location& loc = std::source_location::current()) {\r\n    std::cout << "[" << level_to_string(level) << "] "\r\n              << loc.file_name() << ":" << loc.line()\r\n              << " (" << loc.function_name() << "): "\r\n              << message << "\\n";\r\n}\r\n\r\n// \u65ad\u8a00\u66ff\u4ee3\r\nvoid my_assert(bool condition, std::string_view message = "",\r\n               const std::source_location& loc = std::source_location::current()) {\r\n    if (!condition) {\r\n        std::cout << "\u65ad\u8a00\u5931\u8d25! "\r\n                  << loc.file_name() << ":" << loc.line()\r\n                  << " (" << loc.function_name() << ")";\r\n        if (!message.empty()) {\r\n            std::cout << " - " << message;\r\n        }\r\n        std::cout << "\\n";\r\n    }\r\n}\r\n\r\n// \u51fd\u6570\u8ffd\u8e2a\u5668\r\nclass FunctionTracer {\r\npublic:\r\n    explicit FunctionTracer(const std::source_location& loc = std::source_location::current())\r\n        : location_(loc) {\r\n        std::cout << ">>> \u8fdb\u5165 " << location_.function_name()\r\n                  << " (" << location_.file_name() << ":" << location_.line() << ")\\n";\r\n    }\r\n\r\n    ~FunctionTracer() {\r\n        std::cout << "<<< \u79bb\u5f00 " << location_.function_name() << "\\n";\r\n    }\r\n\r\nprivate:\r\n    std::source_location location_;\r\n};\r\n\r\n// \u6027\u80fd\u68c0\u6d4b\u5668\u7684\u7b80\u5316\u7248\r\nclass ScopeTimer {\r\npublic:\r\n    explicit ScopeTimer(const std::source_location& loc = std::source_location::current())\r\n        : location_(loc) {\r\n        std::cout << "[\u8ba1\u65f6\u5f00\u59cb] " << location_.function_name()\r\n                  << " \u884c " << location_.line() << "\\n";\r\n    }\r\n\r\n    ~ScopeTimer() {\r\n        std::cout << "[\u8ba1\u65f6\u7ed3\u675f] " << location_.function_name()\r\n                  << " \u884c " << location_.line() << "\\n";\r\n    }\r\n\r\nprivate:\r\n    std::source_location location_;\r\n};\r\n\r\nvoid do_some_work() {\r\n    FunctionTracer tracer;  // \u81ea\u52a8\u8bb0\u5f55\u8fdb\u5165\u548c\u79bb\u5f00\r\n    std::cout << "  \u6b63\u5728\u6267\u884c\u5de5\u4f5c...\\n";\r\n}\r\n\r\nvoid process_data() {\r\n    FunctionTracer tracer;\r\n    std::cout << "  \u5904\u7406\u6570\u636e...\\n";\r\n    do_some_work();\r\n    std::cout << "  \u6570\u636e\u5904\u7406\u5b8c\u6210\\n";\r\n}\r\n\r\nvoid advanced_usage() {\r\n    std::cout << "\\n--- \u9ad8\u7ea7\u7528\u6cd5 ---\\n\\n";\r\n\r\n    // \u65e5\u5fd7\u7cfb\u7edf\u6f14\u793a\r\n    std::cout << "-- \u65e5\u5fd7\u7cfb\u7edf --\\n";\r\n    log(LogLevel::INFO, "\u7a0b\u5e8f\u542f\u52a8");\r\n    log(LogLevel::DEBUG, "\u52a0\u8f7d\u914d\u7f6e\u6587\u4ef6");\r\n    log(LogLevel::WARNING, "\u914d\u7f6e\u9879\u7f3a\u5931\uff0c\u4f7f\u7528\u9ed8\u8ba4\u503c");\r\n    log(LogLevel::ERROR, "\u8fde\u63a5\u6570\u636e\u5e93\u5931\u8d25");\r\n\r\n    // \u65ad\u8a00\u6f14\u793a\r\n    std::cout << "\\n-- \u65ad\u8a00 --\\n";\r\n    my_assert(1 + 1 == 2, "\u57fa\u672c\u6570\u5b66\u68c0\u67e5");\r\n    my_assert(1 + 1 == 3, "\u8fd9\u4e2a\u4f1a\u5931\u8d25");\r\n\r\n    // \u51fd\u6570\u8ffd\u8e2a\r\n    std::cout << "\\n-- \u51fd\u6570\u8ffd\u8e2a --\\n";\r\n    process_data();\r\n\r\n    // \u5728Lambda\u4e2d\u4f7f\u7528\r\n    std::cout << "\\n-- Lambda \u4e2d\u4f7f\u7528 --\\n";\r\n    auto lambda_log = [](std::string_view msg,\r\n                          const std::source_location& loc = std::source_location::current()) {\r\n        std::cout << "[Lambda] " << loc.function_name() << ":" << loc.line()\r\n                  << " - " << msg << "\\n";\r\n    };\r\n\r\n    lambda_log("\u4ece Lambda \u8bb0\u5f55\u65e5\u5fd7");\r\n\r\n    // \u5b58\u50a8\u4f4d\u7f6e\u4fe1\u606f\r\n    std::cout << "\\n-- \u5b58\u50a8\u4f4d\u7f6e\u4fe1\u606f --\\n";\r\n    struct LogEntry {\r\n        LogLevel level;\r\n        std::string message;\r\n        std::source_location location;\r\n    };\r\n\r\n    std::vector<LogEntry> log_entries;\r\n    auto add_log = [&log_entries](LogLevel level, std::string message,\r\n                                   const std::source_location& loc = std::source_location::current()) {\r\n        log_entries.push_back({level, std::move(message), loc});\r\n    };\r\n\r\n    add_log(LogLevel::INFO, "\u7b2c\u4e00\u6761\u65e5\u5fd7");\r\n    add_log(LogLevel::WARNING, "\u7b2c\u4e8c\u6761\u65e5\u5fd7");\r\n\r\n    std::cout << "\u5df2\u8bb0\u5f55 " << log_entries.size() << " \u6761\u65e5\u5fd7:\\n";\r\n    for (const auto& entry : log_entries) {\r\n        std::cout << "  [" << level_to_string(entry.level) << "] "\r\n                  << entry.location.line() << ": " << entry.message << "\\n";\r\n    }\r\n}\r\n\r\n// ===================== pitfalls() =====================\r\nvoid pitfalls() {\r\n    std::cout << "\\n--- \u6613\u9519\u70b9 ---\\n\\n";\r\n\r\n    // \u9677\u96311\uff1asource_location::current() \u5728\u53c2\u6570\u9ed8\u8ba4\u503c\u4e2d\u7684\u884c\u4e3a\r\n    std::cout << "1. current() \u5728\u4e0d\u540c\u4f4d\u7f6e\u7684\u884c\u4e3a:\\n";\r\n    std::cout << "   \u4f5c\u4e3a\u9ed8\u8ba4\u53c2\u6570: \u6355\u83b7\u8c03\u7528\u70b9\u7684\u4f4d\u7f6e\uff08\u901a\u5e38\u662f\u4f60\u60f3\u8981\u7684\uff09\\n";\r\n    std::cout << "   \u5728\u51fd\u6570\u4f53\u5185: \u6355\u83b7\u51fd\u6570\u4f53\u5185\u8be5\u884c\u7684\u4f4d\u7f6e\uff08\u901a\u5e38\u4e0d\u662f\u4f60\u60f3\u8981\u7684\uff09\\n";\r\n    std::cout << "   \u5173\u952e\uff1a\u5fc5\u987b\u653e\u5728\u9ed8\u8ba4\u53c2\u6570\u4e2d\uff0c\u4e0d\u80fd\u653e\u5728\u51fd\u6570\u4f53\u91cc!\\n\\n";\r\n\r\n    // \u6f14\u793a\uff1a\u9519\u8bef\u7528\u6cd5\r\n    auto bad_log = [](std::string_view msg) {\r\n        auto loc = std::source_location::current();  // \u6355\u83b7\u7684\u662f\u8fd9\u91cc\u7684\u4f4d\u7f6e!\r\n        std::cout << "   [\u9519\u8bef\u65b9\u5f0f] " << loc.function_name() << ":" << loc.line()\r\n                  << " - " << msg << "\\n";\r\n    };\r\n\r\n    auto good_log = [](std::string_view msg,\r\n                        const std::source_location& loc = std::source_location::current()) {\r\n        std::cout << "   [\u6b63\u786e\u65b9\u5f0f] " << loc.function_name() << ":" << loc.line()\r\n                  << " - " << msg << "\\n";\r\n    };\r\n\r\n    bad_log("\u8fd9\u91cc\u7684\u884c\u53f7\u662f\u51fd\u6570\u4f53\u5185\u90e8\u7684\u884c\u53f7");\r\n    good_log("\u8fd9\u91cc\u7684\u884c\u53f7\u662f\u8c03\u7528\u70b9\u7684\u884c\u53f7");\r\n\r\n    // \u9677\u96312\uff1a\u4e0e\u5b8f\u7684\u4ea4\u4e92\r\n    std::cout << "\\n2. source_location \u4e0d\u53d7\u5b8f\u5c55\u5f00\u5f71\u54cd:\\n";\r\n    std::cout << "   \u5b8f __FILE__ \u548c __LINE__ \u5728\u9884\u5904\u7406\u9636\u6bb5\u5c55\u5f00\\n";\r\n    std::cout << "   source_location \u5728\u7f16\u8bd1\u9636\u6bb5\u5904\u7406\\n";\r\n    std::cout << "   \u4e24\u8005\u53ef\u80fd\u7ed9\u51fa\u4e0d\u540c\u7684\u7ed3\u679c\\n\\n";\r\n\r\n    // \u9677\u96313\uff1asource_location \u5927\u5c0f\r\n    std::cout << "3. source_location \u7684\u5927\u5c0f:\\n";\r\n    std::cout << "   sizeof(source_location) = " << sizeof(std::source_location) << " \u5b57\u8282\\n";\r\n    std::cout << "   \u5b83\u5b58\u50a8\u7684\u662f\u6307\u9488\uff08\u6307\u5411\u7f16\u8bd1\u5668\u751f\u6210\u7684\u5b57\u7b26\u4e32\u8868\uff09\uff0c\u901a\u5e38\u5f88\u5c0f\\n\\n";\r\n\r\n    // \u9677\u96314\uff1a\u51fd\u6570\u540d\u7684\u683c\u5f0f\r\n    std::cout << "4. function_name() \u8fd4\u56de\u7684\u683c\u5f0f\u56e0\u7f16\u8bd1\u5668\u800c\u5f02:\\n";\r\n    std::cout << "   GCC: \u53ef\u80fd\u5305\u542b\u53c2\u6570\u7c7b\u578b\u548c\u8fd4\u56de\u7c7b\u578b\\n";\r\n    std::cout << "   MSVC: \u901a\u5e38\u53ea\u5305\u542b\u51fd\u6570\u540d\\n";\r\n    std::cout << "   \u4e0d\u5e94\u8be5\u89e3\u6790\u51fd\u6570\u540d\u5b57\u7b26\u4e32\u6765\u63d0\u53d6\u4fe1\u606f\\n";\r\n}\r\n\r\n// ===================== main() =====================\r\nint main() {\r\n    std::cout << "===== std::source_location - C++20 =====\\n\\n";\r\n\r\n    basic_usage();\r\n    advanced_usage();\r\n    pitfalls();\r\n\r\n    return 0;\r\n}\n'})}),"\n",(0,e.jsx)(r.h2,{id:"\u53c2\u8003\u94fe\u63a5",children:"\u53c2\u8003\u94fe\u63a5"}),"\n",(0,e.jsxs)(r.ul,{children:["\n",(0,e.jsx)(r.li,{children:(0,e.jsx)(r.a,{href:"https://en.cppreference.com/w/cpp/utility/source_location",children:"cppreference: std::source_location"})}),"\n"]})]})}function d(n={}){const{wrapper:r}={...(0,c.R)(),...n.components};return r?(0,e.jsx)(r,{...n,children:(0,e.jsx)(u,{...n})}):u(n)}},28453(n,r,o){o.d(r,{R:()=>s,x:()=>l});var t=o(96540);const e={},c=t.createContext(e);function s(n){const r=t.useContext(c);return t.useMemo(function(){return"function"==typeof n?n(r):{...r,...n}},[r,n])}function l(n){let r;return r=n.disableParentContext?"function"==typeof n.components?n.components(e):n.components||e:s(n.components),t.createElement(c.Provider,{value:r},n.children)}}}]);